Labyrinth#include &lt;bits/stdc++.h&gt;#define int long long#define pii pair&lt;int, int&gt;#define F first#define S second#define rep(i, a, b) for(int i = a; i&lt;=b; ++i)#define rev(i, a, b) for(int i = a; i&gt;=b; --i)#define tomax(a, b) (a)=max((a),(b))#define tomin(a, b) (a)=min((a),(b))#define all(a) a.begin(), a.end()#define pob pop_back#define pb push_back#define eb emplace_back#define ios ios_base::sync_with_stdio(0), cin.tie(0), cout.tie(0)using namespace std;int n, m;pii a, b;bool find_path = false;bool graph[1003][1003];queue&lt;pii&gt; q;vector&lt;char&gt; path;int dir[1003][1003];signed main()&#123;    ios;    memset(graph, 0, sizeof(graph));    cin &gt;&gt; n &gt;&gt; m;    char tmp;    rep(i, 1, n)        rep(j, 1, m)            cin &gt;&gt; tmp, graph[j][i]=(tmp!=&#x27;#&#x27;&amp;&amp;tmp!=&#x27;A&#x27;),            a = (tmp==&#x27;A&#x27; ? make_pair(j,i) : a),            b = (tmp==&#x27;B&#x27; ? make_pair(j,i) : b);    q.push(a);    while(q.size())&#123;        int x = q.front().F, y = q.front().S; q.pop();        if(x==b.F &amp;&amp; y==b.S)&#123; find_path=true; break;&#125;        if(graph[x-1][y]) dir[x-1][y]=&#x27;L&#x27;, graph[x-1][y]=0, q.push(&#123;x-1, y&#125;);        if(graph[x+1][y]) dir[x+1][y]=&#x27;R&#x27;, graph[x+1][y]=0, q.push(&#123;x+1, y&#125;);        if(graph[x][y-1]) dir[x][y-1]=&#x27;U&#x27;, graph[x][y-1]=0, q.push(&#123;x, y-1&#125;);        if(graph[x][y+1]) dir[x][y+1]=&#x27;D&#x27;, graph[x][y+1]=0, q.push(&#123;x, y+1&#125;);    &#125;    if(!find_path)&#123;cout &lt;&lt; &quot;NO
&quot;; return 0;&#125;    while(a!=b)&#123;        path.pb(dir[b.F][b.S]);        if(dir[b.F][b.S]==&#x27;L&#x27;) b=&#123;b.F+1, b.S&#125;;        else if(dir[b.F][b.S]==&#x27;R&#x27;) b=&#123;b.F-1, b.S&#125;;        else if(dir[b.F][b.S]==&#x27;U&#x27;) b=&#123;b.F, b.S+1&#125;;        else if(dir[b.F][b.S]==&#x27;D&#x27;) b=&#123;b.F, b.S-1&#125;;    &#125;reverse(all(path));    cout &lt;&lt; &quot;YES
&quot; &lt;&lt; path.size() &lt;&lt; &#x27;
