Message Route#include &lt;bits/stdc++.h&gt;#define int long long#define pii pair&lt;int, int&gt;#define F first#define S second#define rep(i, a, b) for (int i = a; i &lt;= b; ++i)#define rev(i, a, b) for (int i = a; i &gt;= b; --i)#define tomax(a, b) (a) = max((a), (b))#define tomin(a, b) (a) = min((a), (b))#define all(a) a.begin(), a.end()#define pob pop_back#define pb push_back#define eb emplace_back#define ios ios_base::sync_with_stdio(0), cin.tie(0), cout.tie(0)using namespace std;int n, m, tmp1, tmp2;int last_cpu[100005];vector&lt;int&gt; E[100005];vector&lt;int&gt; ans;signed main() &#123;    ios;    // BFS    fill(last_cpu, last_cpu+100005, INT_MAX);    cin &gt;&gt; n &gt;&gt; m;    rep(i, 1, m) cin &gt;&gt; tmp1 &gt;&gt; tmp2, E[tmp1].eb(tmp2), E[tmp2].eb(tmp1);    queue&lt;int&gt; q;    q.push(1); last_cpu[1]=1;    while(!q.empty())&#123;        int cur = q.front();        q.pop();        for(int x : E[cur])            if(last_cpu[x]==INT_MAX) q.push(x), last_cpu[x]=cur;    &#125;    if(last_cpu[n]!=INT_MAX)&#123;        while(n!=1)&#123;            ans.pb(n);            n=last_cpu[n];        &#125;cout &lt;&lt; ans.size()+1 &lt;&lt; &#x27;
