Building Teams#include &lt;bits/stdc++.h&gt;using namespace std;/* TYPES  */#define int long long#define pii pair&lt;int, int&gt;#define F first#define S second#define vi vector&lt;int&gt;#define mii map&lt;int, int&gt;#define si set&lt;int&gt;/* UTILS */#define rep(i, a, b) for (int i = a; i &lt;= b; ++i)#define rev(i, a, b) for (int i = a; i &gt;= b; --i)#define tomax(a, b) (a) = max((a), (b))#define tomin(a, b) (a) = min((a), (b))#define all(a) a.begin(), a.end()#define rall(a) (a).rbegin(), (a).rend()#define pob pop_back#define pb push_back#define eb emplace_back#define sp &lt;&lt; &quot; &quot; &lt;&lt;#define ios ios_base::sync_with_stdio(0), cin.tie(0), cout.tie(0)vi E[100005];vi team;int n, m, tmp1, tmp2;bool build_team = true;void dfs(int r) &#123;    int draw = team[r] % 2 + 1;    for (int i : E[r]) &#123;        if (team[i] == 0)            team[i] = draw, dfs(i);        else if (team[i] == draw)            continue;        else &#123;            build_team = false;            return;        &#125;    &#125;&#125;signed main() &#123;    ios;    // bipartite graph    cin &gt;&gt; n &gt;&gt; m;    team.resize(n + 1), team.assign(n + 1, 0);    rep(i, 1, m) &#123;        cin &gt;&gt; tmp1 &gt;&gt; tmp2;        E[tmp1].eb(tmp2), E[tmp2].eb(tmp1);    &#125;    rep(i, 1, n) &#123;        if (team[i] == 0) team[i] = 1, dfs(i);    &#125;    if (build_team) &#123;        team.erase(team.begin());        for (int i : team) cout &lt;&lt; i &lt;&lt; &#x27; &#x27;;    &#125; else        cout &lt;&lt; &quot;IMPOSSIBLE&quot;;    return 0;&#125;
Round Trip 
Round Trip#include &lt;bits/stdc++.h&gt;using namespace std;/* TYPES  */#define int long long#define pii pair&lt;int, int&gt;#define F first#define S second#define vi vector&lt;int&gt;#define mii map&lt;int, int&gt;#define si set&lt;int&gt;/* UTILS */#define rep(i, a, b) for (int i = a; i &lt;= b; ++i)#define rev(i, a, b) for (int i = a; i &gt;= b; --i)#define tomax(a, b) (a) = max((a), (b))#define tomin(a, b) (a) = min((a), (b))#define all(a) a.begin(), a.end()#define rall(a) (a).rbegin(), (a).rend()#define pob pop_back#define pb push_back#define eb emplace_back#define sp &lt;&lt; &quot; &quot; &lt;&lt;#define ios ios_base::sync_with_stdio(0), cin.tie(0), cout.tie(0)int n, m, min_l = INT_MAX, min_ls, min_le;vi E[100005];int lev[100005], parent[100005];bool vis[100005];void dfs(int u) &#123;    if (vis[u]) return;    vis[u] = 1;    for (int i : E[u]) &#123;        if (!vis[i])            lev[i] = lev[u] + 1, parent[i] = u, dfs(i);        else if(lev[u] &gt; lev[i] &amp;&amp; i != parent[u])&#123;            int path = lev[u] - lev[i] + 2;            if (path &lt; min_l) min_l=path, min_ls = u, min_le = i;        &#125;    &#125;&#125;signed main() &#123;    ios;    int tmp1, tmp2;    memset(vis, 0, sizeof(vis));    memset(lev, 0, sizeof(lev));    cin &gt;&gt; n &gt;&gt; m;    rep(i, 1, m) cin &gt;&gt; tmp1 &gt;&gt; tmp2, E[tmp1].eb(tmp2), E[tmp2].eb(tmp1);    rep(i, 1, n) dfs(i);    if(min_l == INT_MAX) cout &lt;&lt; &quot;IMPOSSIBLE
&quot;;    else&#123;        cout &lt;&lt; min_l &lt;&lt; &#x27;
&#x27;;        tmp1 = min_ls;        rep(i, 2, min_l)&#123;            cout &lt;&lt; min_ls &lt;&lt; &#x27; &#x27;;            min_ls = parent[min_ls];        &#125;cout &lt;&lt; tmp1 &lt;&lt; &#x27;
&#x27;;    &#125;    return 0;&#125;
