Monsters#include &lt;bits/stdc++.h&gt;using namespace std;/* TYPES  */// #define int long long#define pii pair&lt;int, int&gt;#define F first#define S second#define vc vector#define vi vector&lt;int&gt;#define vii vector&lt;pii&gt;#define mii map&lt;int, int&gt;#define si set&lt;int&gt;/* UTILS */#define rep(i, a, b) for (int i = a; i &lt;= b; ++i)#define rev(i, a, b) for (int i = a; i &gt;= b; --i)#define tomax(a, b) (a) = max((a), (b))#define tomin(a, b) (a) = min((a), (b))#define all(a) a.begin(), a.end()#define rall(a) (a).rbegin(), (a).rend()#define pob pop_back#define pb push_back#define eb emplace_back#define ins insert#define err(a) cerr &lt;&lt; #a &lt;&lt; &quot;: &quot; &lt;&lt; a &lt;&lt; &quot;
&quot;#define sp &lt;&lt; &quot; &quot; &lt;&lt;#define ios ios_base::sync_with_stdio(0), cin.tie(0), cout.tie(0)bool vis[1003][1003];bool vis_h[1003][1003];signed main() &#123;    ios;    int n, m;    char g[1003][1003];    cin &gt;&gt; n &gt;&gt; m;    queue&lt;pair&lt;pii, bool&gt; &gt; pt;    int from[1003][1003];    bool ok = 0;    pair&lt;pii, bool&gt; a;    pii de;    int dir_x[5] = &#123;1, 0, -1, 0&#125;, dir_y[5] = &#123;0, 1, 0, -1&#125;;    char dir[5] = &#123;&#x27;D&#x27;, &#x27;R&#x27;, &#x27;U&#x27;, &#x27;L&#x27;&#125;;    rep(i, 0, n - 1) rep(j, 0, m - 1) &#123;        cin &gt;&gt; g[i][j];        if (g[i][j] == &#x27;#&#x27;) vis[i][j] = 1;        if (g[i][j] == &#x27;M&#x27;) pt.push(&#123;&#123;i, j&#125;, 0&#125;), vis[i][j] = 1;        if (g[i][j] == &#x27;A&#x27;) a = &#123;&#123;i, j&#125;, 1&#125;, vis_h[i][j] = 1;    &#125;    pt.push(a);    while (!pt.empty()) &#123;        // 0 U, 1 R, 2 D, 3 L        auto x = pt.front();        pt.pop();        // cout &lt;&lt; x.F.F sp x.F.S &lt;&lt; &#x27;
&#x27;;        if (!x.S) &#123;            rep(i, 0, 3) &#123;                int xx = x.F.F + dir_x[i], yy = x.F.S + dir_y[i];                if (!vis[xx][yy] &amp;&amp; xx &gt;= 0 &amp;&amp; xx &lt;= n - 1 &amp;&amp; yy &gt;= 0 &amp;&amp;                    yy &lt;= m - 1) &#123;                    pt.push(&#123;&#123;xx, yy&#125;, 0&#125;);                    vis[xx][yy] = 1;                &#125;            &#125;        &#125; else if (x.S &amp;&amp; (x.F.F == 0 || x.F.S == 0 || x.F.F == n - 1 ||                           x.F.S == m - 1)) &#123;            // cout &lt;&lt; x.F.F sp x.F.S &lt;&lt; &#x27;
&#x27;;            ok = 1;            de = &#123;x.F.F, x.F.S&#125;;            break;        &#125; else if (x.S) &#123;            // cout &lt;&lt; x.F.F sp x.F.S &lt;&lt; &#x27;
&#x27;;            // cout &lt;&lt; &#x27;
&#x27;;            rep(i, 0, 3) &#123;                if (!vis[x.F.F + dir_x[i]][x.F.S + dir_y[i]] &amp;&amp;                    !vis_h[x.F.F + dir_x[i]][x.F.S + dir_y[i]]) &#123;                    pt.push(&#123;&#123;x.F.F + dir_x[i], x.F.S + dir_y[i]&#125;, 1&#125;);                    vis_h[x.F.F + dir_x[i]][x.F.S + dir_y[i]] = 1;                    from[x.F.F + dir_x[i]][x.F.S + dir_y[i]] = i;                &#125;            &#125;        &#125;    &#125;    if (!ok)        cout &lt;&lt; &quot;NO
&quot;;    else &#123;        cout &lt;&lt; &quot;YES
&quot;;        vector&lt;char&gt; ans;        while (de.F != a.F.F || de.S != a.F.S) &#123;            // cout &lt;&lt; de.F sp de.S &lt;&lt; &#x27;
&#x27;;            int tmpF = de.F;            ans.eb(dir[from[de.F][de.S]]);            de.F -= dir_x[from[de.F][de.S]];            de.S -= dir_y[from[tmpF][de.S]];            // cout &lt;&lt; de.F sp de.S &lt;&lt; &quot;

&quot;;        &#125;        cout &lt;&lt; ans.size() &lt;&lt; &#x27;
