Kruskal's Algorithm O(N log N)#include &lt;bits/stdc++.h&gt;#define N 200005#define edge pair&lt;int, pair&lt;int, int&gt; &gt;#define u first#define v second.first#define w second.second#define int long longusing namespace std;int boss[N], n, m;edge E[N];bool cmp(edge a, edge b)&#123;    return a.w &lt; b.w;&#125;int find_boss(int x)&#123;    if(x == boss[x])    return x;    return boss[x] = find_boss(boss[x]);  //路徑壓縮&#125;signed main()&#123;    ios::sync_with_stdio(0);    cin.tie(0);    while(cin &gt;&gt; n &gt;&gt; m)&#123;        int num_edge = 0;        for(int i = 0; i&lt;n; i++) boss[i] = i;        for(int i = 0; i&lt;m; i++) cin &gt;&gt; E[i].u &gt;&gt; E[i].v &gt;&gt; E[i].w;        sort(E, E+m, cmp);        int ans = 0;                   for(int i = 0; i&lt;m; i++)&#123;            int a = find_boss(E[i].u), b = find_boss(E[i].v);            if(a!=b)&#123;                boss[b] = a;                ans += E[i].w;                num_edge++;            &#125;        &#125;        if(num_edge == n-1)            cout &lt;&lt; ans &lt;&lt; &#x27;\n&#x27;;        else cout &lt;&lt; &quot;-1\n&quot;;    &#125;        return 0;&#125;
