Prim's Algorithm(跟最短路徑的Dijkstra很像) O(N log N)#include &lt;bits/stdc++.h&gt;#define N 200005#define pii pair&lt;int, int&gt;#define w first#define to second#define int long longusing namespace std;signed main()&#123;    ios::sync_with_stdio(0);    cin.tie(0);    int n, m;    while(cin &gt;&gt; n &gt;&gt; m)&#123;        vector&lt;pii&gt; E[N];        int num_edge = 0, ans = 0;        for(int i = 0, u, v, w; i&lt;m; i++)            cin &gt;&gt; u &gt;&gt; v &gt;&gt; w, E[u].push_back(&#123;w,v&#125;), E[v].push_back(&#123;w, u&#125;);        priority_queue&lt;pii, vector&lt;pii&gt;, greater&lt;pii&gt;&gt; q;        bool vis[N]; memset(vis, 0, sizeof(vis)); vis[0] = 1;        for(pii x : E[0]) q.push(x);        while(!q.empty())&#123;            pii cur = q.top(); q.pop();             if(vis[cur.to]) continue;            vis[cur.to] = 1, num_edge++;            ans += cur.w;            for(pii x : E[cur.to]) q.push(x);        &#125;        if(num_edge == n-1)            cout &lt;&lt; ans &lt;&lt; &#x27;\n&#x27;;        else cout &lt;&lt; &quot;-1\n&quot;;    &#125;        return 0;&#125;
